/*
 * ApexVelocity — client-side navigation wiring.
 * The page markup is generated by Google Stitch (self-contained, all links are "#").
 * This script makes the static site browsable by routing links/buttons to the
 * correct page based on their text/icon, without mutating the generated design.
 */
(function () {
  "use strict";

  var PAGES = {
    home: "index.html",
    shop: "shop.html",
    product: "product.html",
    checkout: "checkout.html",
  };

  // Normalized link text  ->  destination page
  var TEXT_ROUTES = {
    apexvelocity: PAGES.home,
    men: PAGES.shop,
    women: PAGES.shop,
    accessories: PAGES.shop,
    sports: PAGES.shop,
    sport: PAGES.shop,
    running: PAGES.shop,
    training: PAGES.shop,
    cycling: PAGES.shop,
    "shop now": PAGES.shop,
    "shop new arrivals": PAGES.shop,
    "explore gear": PAGES.shop,
    "view all": PAGES.shop,
    "view all products": PAGES.shop,
    "newest arrivals": PAGES.shop,
    "quick add": PAGES.checkout,
    "add to cart": PAGES.checkout,
    "buy now": PAGES.checkout,
    "proceed to checkout": PAGES.checkout,
    "place order": PAGES.checkout,
    "complete order": PAGES.checkout,
  };

  function norm(el) {
    return (el.textContent || "").trim().toLowerCase().replace(/\s+/g, " ");
  }

  function go(href) {
    return function (e) {
      e.preventDefault();
      window.location.href = href;
    };
  }

  // 1) Route anchors + buttons by their text label.
  document.querySelectorAll("a, button").forEach(function (el) {
    var dest = TEXT_ROUTES[norm(el)];
    if (dest) {
      el.style.cursor = "pointer";
      el.addEventListener("click", go(dest));
    }
  });

  // 2) The cart icon (material symbol) routes to checkout.
  document.querySelectorAll(".material-symbols-outlined").forEach(function (icon) {
    if ((icon.textContent || "").trim() === "shopping_cart") {
      var btn = icon.closest("a, button") || icon;
      btn.style.cursor = "pointer";
      btn.addEventListener("click", go(PAGES.checkout));
    }
  });

  // 3) Product cards (any card wrapping a product <img>) open the product page.
  //    Skip on the product page itself so gallery thumbnails stay put.
  var isProductPage = /product\.html$/i.test(window.location.pathname);
  if (!isProductPage) {
    document.querySelectorAll("main img").forEach(function (img) {
      var card = img.closest(".group");
      if (card && !card.dataset.wired) {
        card.dataset.wired = "1";
        card.style.cursor = "pointer";
        card.addEventListener("click", function (e) {
          // let inner buttons (Quick Add, etc.) handle their own clicks
          if (e.target.closest("button")) return;
          window.location.href = PAGES.product;
        });
      }
    });
  }
})();
